  ('aboriginal-64311456-moex-00376', 'aboriginal-64311456', 'aboriginal-64311456-moex-110-d1a761c9', 'sub-aboriginal-64311456-12', NULL, 'single_choice', '甲於公園內丟棄垃圾，被公園管理人拍照舉發，由主管機關處以法定裁罰最高額新臺幣6,000元罰鍰， 甲得為下列何種抗辯？ 公園管理人不應私下拍照舉發，應不罰 應視違規情節輕重程度裁罰，不應逕以最高額裁罰 甲已事後將垃圾清除，應不罰 他人已協助事後將垃圾清除，應不罰', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:09+00:00", "source_pdf_sha1": "ce8d78e19484", "answer_pdf_sha1": "cf08cb006ead", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "503", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aboriginal", "civil_category": "社會行政"}'::jsonb, NULL)
